  ('heelevel3-6f0ba476-moex-00594', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '假設甲有固定的所得，他申報所得，政府對他申報的所得課徵比例稅率的所得稅，並且以一定機 率稽核他的真實所得。若被查到漏報所得，則甲除了補繳他所逃漏的所得稅外，還必須就他所逃 漏的稅額繳納罰款。假設甲極大化他的預期所得且他沒有誠實申報，下列敘述何者錯誤？', '["提高稅率會降低甲漏報所得的誘因", "提高稽核率會降低甲漏報所得的誘因", "提高罰款會降低甲漏報所得的誘因", "甲會有一個最適的逃漏所得水準"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "87eeb6c1355b", "answer_pdf_sha1": "f7be461b00b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
